// Extrai e parseia a resposta do Claude
const response = $input.first().json;
const inputData = $('Validar Input').first().json;

let aiData = {};
try {
  const content = response.content?.[0]?.text || '{}';
  // Tenta extrair JSON mesmo se houver texto extra
  const match = content.match(/\{[\s\S]*\}/);
  if (match) aiData = JSON.parse(match[0]);
} catch (e) {
  aiData = {};
}

// Merge com input original
const result = {
  word: aiData.word || inputData.word,
  type: aiData.type || 'word',
  ipa: aiData.ipa || '',
  meaning_pt: aiData.meaning_pt || '',
  examples: aiData.examples || [],
  level: aiData.level || '',
  tags: aiData.tags || [],
  context: inputData.context,
  source_type: inputData.source_type,
  source_title: inputData.source_title,
  processed: true,
  processed_at: new Date().toISOString()
};

return [{ json: result }];

// Combina dados processados com áudio base64
const aiResult = $('Parsear Resposta IA').first().json;
const ttsResponse = $input.first();

let audioBase64 = null;
try {
  // n8n retorna binary data — pega o base64
  audioBase64 = ttsResponse.binary?.data?.data || null;
} catch { audioBase64 = null; }

return [{
  json: {
    ...aiResult,
    audio_base64: audioBase64
  }
}];
